// Learn: Normalize and inspect a String.
String raw = "  admin@example.com  ";
String email = raw.trim().toLowerCase();
boolean internal = email.endsWith("@example.com");
if (!email.isBlank() && email.contains("admin")) {
  // substring reads characters from index 0 up to 5.
  System.out.println(email.substring(0, 5));
}
